#!/usr/bin/env bash
# workflow-1.sh — 个人号矩阵迁移到企业微信（一次性迁移工程） SOP walkthrough for 微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="微信私域运营 (企微 + 个人号 + 公众号 + 视频号 + 小程序 + 朋友圈 + 社群 全链路 — 引流 / 沉淀 / 触达 / 转化 / 复购 / 裂变)"
WORKFLOW="个人号矩阵迁移到企业微信（一次性迁移工程）"

usage() {
  cat <<EOF
workflow-1.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./workflow-1.sh             # interactive
  ./workflow-1.sh --dry-run
  ./workflow-1.sh --json
  ./workflow-1.sh --explain
  ./workflow-1.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "个人号矩阵迁移到企业微信（一次性迁移工程）" 工作流。

一句话: 一个还在用「个人微信号矩阵」做私域的商家，从「一堆个人号、随时面临封号、客户不可继承」状态，迁移到「企业微信主体、合规、客户可继承、可 API 化」——这是 2024 起企微成 default 后的「历史包袱清算」工程。

入门 SOP 共 6 步, 失败模式自检 4 项。

相关心智模型:
  • 公私二分 / 流量自主权（mental model）: 私域人看一切流量的底层镜片是「这部分流量是租来的还是自己的」——租来的（公域）用一次付一次、平台控分发，自己的（私域）可反复免费触达；近年这对二分从「对立」演化为「全域协同」，但「自主权」这条轴没变。
  • 流量池 / 蓄水养鱼（mental model）: 私域人把流量当成「要蓄进池子、反复经营」的对象而非「这次能转化多少」的一次性曝光——但「建了群 / 加了好友」只是蓄了水，**没有运营动作的池是死水**；价值在「蓄水—养鱼—捕鱼」的循环，不在池子大小

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**盘点存量资产**：清点现有个人号数量、各号好友量、客户质量与标签现状，确定哪些客户必须迁、哪些可放弃。who: 私域负责人。"
  "**搭企微组织架构**：注册 / 配置企业微信主体，建好部门 / 成员 / 客服号，规划企微侧的人设与分工（对应 W1 step 2）。"
  "**设计迁移引导**：设计「从个人号引导客户加企微」的话术与钩子（如「我们升级了企业服务号，加这个享专属权益」），分批引导而非一次性硬迁。"
  "**执行客户迁移 / 继承**：用企业微信官方的「在职继承 / 离职继承」机制做规范迁移——管理员在后台【客户联系】中选在职 / 离职继承，筛选客户分配给接收成员，客户在约 24 小时后自动成为继承成员的联系人。(evidence: [T03-S001])"
  "**迁移后清洗 / 补标**：迁移后核对——企业标签会同步过去，但**前一员工与客户的聊天记录、个人标签不会同步**，需在企微侧重新补打标签、整理客户档案。(evidence: [T03-S001])"
  "**切换增量入口 + 降级个人号**：把所有新增引流入口（活码等）切到企微，个人号停止新增、降级为辅助或逐步弃用。"
)
declare -a FAILURE_MODES=(
  "**靠人工重新加好友硬迁**: 触发原因 = 不知道 / 不用企微官方继承机制。怎么避免 = 用官方「在职 / 离职继承」做规范迁移，先读懂分配次数与保护期规则。"
  "**以为标签和聊天记录都会跟过来**: 触发原因 = 不了解同步范围。怎么避免 = 明确「企业标签同步、聊天记录和个人标签不同步」，迁移后预留清洗补标工作量。"
  "**CLI 化暗示 (v0.6+)**: Migrate by manually re-adding every personal-account contact instead of using WeCom's official inheritance — slow, error-prone, and you lose contacts; also blocked by the 2-assignments / 90-day-protection rules you didn't read."
  "**CLI 化暗示 (v0.6+)**: Assume tags and chat history transfer with the customer — they don't (only enterprise tags do), so post-migration your customers look \"amnesiac\" and operations break. Budget time to re-tag after migration."
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "workflow-1-walkthrough"
fi
